      signals.push("Delayed shipment");

    if (supportCases.some(c => c.status === "open" && ["high", "critical"].includes(c.severity)))
      signals.push("Escalated support");

    if (usage.currentPeriodUnits <= usage.priorPeriodUnits * 0.7)
      signals.push("Usage decline");

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(tier) && signals.length > 0;

    let status, riskSummary, nextStep, owners;

    if (!qualifies) {
      status = "Monitoring — no escalation required.";
      riskSummary = `${signals.length} signals${signals.length ? ": " + signals.join(", ") : ""}`;
      nextStep = "Continue standard monitoring.";
      owners = [];
    } else {
      status = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
      riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
      owners = [];
      if (signals.includes("Regulatory hold")) owners.push("Legal");
      if (signals.includes("Overdue invoice")) owners.push("Finance");
      if (signals.includes("Delayed shipment") || signals.includes("Usage decline")) owners.push("Customer Success");
      if (signals.includes("Escalated support")) owners.push("Support");
      nextStep = `${owners[0]} recovery review by 16:00`;
    }

    await db.collection("workflow_state").deleteMany({});
    await db.collection("owner_tasks").deleteMany({});
    await db.collection("customer_messages").deleteMany({});
    await db.collection("audit_events").deleteMany({});

    await db.collection("workflow_state").insertOne({
      status,
      next_step: nextStep,
      risk_summary: riskSummary,
      created_at: now,
    });

    if (owners.length > 0) {
      const dueAt = new Date(new Date(now).getTime() + 24 * 60 * 60 * 1000).toISOString();
      await db.collection("owner_tasks").insertMany(
        owners.map(owner => ({
          owner_group: owner,
          title: `${owner} recovery task for ${account.name}`,
          due_at: dueAt,
          status: "open",
        }))
      );
    }

    const signalDescriptions = {
      "Regulatory hold": "a compliance review in progress",
      "Overdue invoice": "an outstanding payment requiring attention",
      "Delayed shipment": "a delayed delivery",
      "Escalated support": "an open support issue requiring prompt resolution",
      "Usage decline": "a significant change in usage patterns",
    };

    if (qualifies) {
      const phrases = signals.map(s => signalDescriptions[s]);
      const body = `Dear ${account.name} team, we have identified ${phrases.length} area${phrases.length > 1 ? "s" : ""} requiring immediate attention for your account: ${phrases.join(", ")}. Our dedicated recovery team has been engaged and will be in contact shortly to ensure a swift resolution. We value your continued partnership.`;
      await db.collection("customer_messages").insertOne({ body, created_at: now });
    } else {
      const body = `Dear ${account.name} team, your account is currently under standard monitoring. No immediate action is required at this time. We will continue to review your account health and will reach out if anything changes.`;
      await db.collection("customer_messages").insertOne({ body, created_at: now });
    }

    await db.collection("audit_events").insertOne({
      event_type: qualifies ? "escalation_initiated" : "monitoring_review",
      description: qualifies
        ? `Escalation triggered with ${riskSummary.toLowerCase()}.`
        : "Account reviewed — no escalation required.",
      customer_visible: true,
      created_at: now,
    });
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
